def generate_candidates(existing: set[str], rng: random.Random) -> list[Candidate]:
    out: list[Candidate] = []

    for act, year, wrong, diff in ACTS:
        pool = wrong + [year]
        years = [y for _, y, _, _ in ACTS]
        _add(out, existing, rng, f"'{act}' പ്രാബല്യത്തിൽ വന്ന വർഷം?", year, pool, diff)
        _add(out, existing, rng, f"{year}-ൽ പ്രാബല്യത്തിൽ വന്ന നിയമം/ആക്ട്?", act, [a for a, _, _, _ in ACTS], diff)

    for battle, year, wrong, diff in BATTLES:
        pool = wrong + [year]
        _add(out, existing, rng, f"'{battle}' യുദ്ധം നടന്ന വർഷം?", year, pool, diff)
        _add(out, existing, rng, f"{year}-ൽ നടന്ന പ്രധാന യുദ്ധം?", battle, [b for b, _, _, _ in BATTLES], diff)

    for viceroy, detail, wrong, diff in VICEROYS:
        pool = wrong + [detail]
        vnames = [v for v, _, _, _ in VICEROYS]
        _add(out, existing, rng, f"വൈസ്രോയി '{viceroy}'-ന് ബന്ധപ്പെട്ട വസ്തു?", detail, pool, diff)
        _add(out, existing, rng, f"'{detail}' ഏത് വൈസ്രോയിയുമായി ബന്ധപ്പെട്ടത്?", viceroy, vnames, diff)

    for dyn, founder, wrong, diff in DYNASTIES:
        pool = wrong + [founder]
        dnames = [d for d, _, _, _ in DYNASTIES]
        fnames = [f for _, f, _, _ in DYNASTIES]
        _add(out, existing, rng, f"'{dyn}' രാജവംശത്തിന്റെ സ്ഥാപകൻ?", founder, pool, diff)
        _add(out, existing, rng, f"'{founder}' ഏത് രാജവംശത്തിന്റെ സ്ഥാപകനാണ്?", dyn, dnames, diff)

    for cap, capital, wrong, diff in DYNASTY_CAPITALS:
        pool = wrong + [capital]
        _add(out, existing, rng, f"'{cap}' രാജവംശത്തിന്റെ തലസ്ഥാനം?", capital, pool, diff)

    for mov, leader, wrong, diff in MOVEMENTS:
        pool = wrong + [leader]
        mnames = [m for m, _, _, _ in MOVEMENTS]
        lnames = [l for _, l, _, _ in MOVEMENTS]
        _add(out, existing, rng, f"'{mov}' പ്രസ്ഥാനത്തിന്റെ നേതാവ്?", leader, pool, diff)
        _add(out, existing, rng, f"'{leader}' ഏത് പ്രസ്ഥാനവുമായി ബന്ധപ്പെട്ടത്?", mov, mnames, diff)

    for book, author, wrong, diff in BOOKS:
        pool = wrong + [author]
        bnames = [b for b, _, _, _ in BOOKS]
        _add(out, existing, rng, f"'{book}' രചയിതാവ്?", author, pool, diff)
        _add(out, existing, rng, f"'{author}'-ന്റെ പ്രധാന ഗ്രന്ഥം?", book, bnames, diff)

    for q, ans, wrong, diff in ANCIENT:
        pool = wrong + [ans]
        _add(out, existing, rng, f"പുരാതന ഇന്ത്യൻ ചരിത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in MEDIEVAL:
        pool = wrong + [ans]
        _add(out, existing, rng, f"മധ്യകാല ഇന്ത്യൻ ചരിത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in MODERN:
        pool = wrong + [ans]
        _add(out, existing, rng, f"ആധുനിക ഇന്ത്യൻ ചരിത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in REVOLUTIONARIES:
        pool = wrong + [ans]
        _add(out, existing, rng, f"സ്വാതന്ത്ര്യ സമര ചരിത്രത്തിൽ '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in GOVERNORS:
        pool = wrong + [ans]
        _add(out, existing, rng, f"ബ്രിട്ടീഷ് ഭരണകാലത്ത് '{q}'?", ans, pool, diff)

    for q, ans, wrong, diff in COMMISSIONS:
        pool = wrong + [ans]
        _add(out, existing, rng, f"ഇന്ത്യൻ ചരിത്രത്തിൽ '{q}'?", ans, pool, diff)

    for act, year, wrong, diff in ACTS:
        pool = wrong + [year]
        _add(out, existing, rng, f"ബ്രിട്ടീഷ് ഭരണകാല '{act}' പ്രാബല്യ വർഷം?", year, pool, diff)
        _add(out, existing, rng, f"'{year}'-ൽ പ്രാബല്യത്തിൽ വന്ന ഇന്ത്യൻ നിയമം?", act,
             [a for a, _, _, _ in ACTS if a != act][:6], diff)

    for battle, year, wrong, diff in BATTLES:
        pool = wrong + [year]
        _add(out, existing, rng, f"ഇന്ത്യൻ/ലോക ചരിത്രത്തിൽ '{battle}' വർഷം?", year, pool, diff)

    for dyn, founder, wrong, diff in DYNASTIES:
        pool = wrong + [founder]
        _add(out, existing, rng, f"'{dyn}'-യുടെ സ്ഥാപകനായി അറിയപ്പെടുന്നവർ?", founder, pool, diff)

    for cap, capital, wrong, diff in DYNASTY_CAPITALS:
        pool = wrong + [capital]
        _add(out, existing, rng, f"'{cap}'-ന്റെ തലസ്ഥാനം?", capital, pool, diff)
        _add(out, existing, rng, f"'{capital}' ഏത് രാജവംശ/സാമ്രാജ്യത്തിന്റെ തലസ്ഥാനം?", cap,
             [c for c, _, _, _ in DYNASTY_CAPITALS], diff)

    return out
